#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char S[500001];
        scanf("%s", S);
        int M, P;
        scanf("%d %d", &M, &P);
        int n = strlen(S);
        int rotations = 0;
        int flag = 0;
        char original[500001];
        strcpy(original, S);
        while (1) {
            // rotate M
            char temp[500001];
            strcpy(temp, S + n - M);
            strcat(temp, S);
            temp[n] = '\0';
            strcpy(S, temp);
            rotations++;
            if (strcmp(S, original) == 0) {
                flag = 1;
                break;
            }
            // rotate P
            strcpy(temp, S + n - P);
            strcat(temp, S);
            temp[n] = '\0';
            strcpy(S, temp);
            rotations++;
            if (strcmp(S, original) == 0) {
                flag = 1;
                break;
            }
            if (rotations > 2 * n) {
                break;
            }
        }
        if (flag) {
            printf("%d\n", rotations);
        } else {
            printf("-1\n");
        }
    }
    return 0;
}

