import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String S = sc.next();
            int M = sc.nextInt();
            int P = sc.nextInt();
            int n = S.length();
            int rotations = 0;
            int flag = 0;
            String original = S;
            while (true) {
                // rotate M
                String temp = S.substring(n - M) + S;
                S = temp;
                rotations++;
                if (S.equals(original)) {
                    flag = 1;
                    break;
                }
                // rotate P
                temp = S.substring(n - P) + S;
                S = temp;
                rotations++;
                if (S.equals(original)) {
                    flag = 1;
                    break;
                }
                if (rotations > 2 * n) {
                    break;
                }
            }
            if (flag == 1) {
                System.out.println(rotations);
            } else {
                System.out.println(-1);
            }
        }
    }
}

